// PersonalAIMentor.jsx
import React, { useEffect, useState, useRef } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებსა და მიზნებზე?",
  ENTP: "გამარჯობა 💡 მოდი ვიფიქროთ კრეატიულად შენს იდეებზე!",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო?"
};

export default function PersonalAIMentor({ userType, userId, memory }) {

  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [currentMBTI, setCurrentMBTI] = useState(userType || "DEFAULT");

  const safeUserId = userId || localStorage.getItem("userId");

  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);
  const firstLoad = useRef(true);

  // ================= SCROLL =================
  const scrollToBottom = () => {
    const container = messagesEndRef.current?.parentElement;
    if (!container) return;

    let current = container.scrollTop;
    const target = container.scrollHeight;
    const velocity = 0.2;
    let animating = true;

    const step = () => {
      if (!animating) return;

      const distance = target - current;
      current += distance * velocity;
      container.scrollTop = current;

      if (Math.abs(distance) > 0.5) {
        requestAnimationFrame(step);
      } else {
        container.scrollTop = target;
        animating = false;
      }
    };

    requestAnimationFrame(step);
  };

  // ================= TYPING GREETING =================
  const typeGreeting = (text) => {
    let i = 0;

    const interval = setInterval(() => {

      setMessages([{ role: "ai", text: text.slice(0, i) }]);

      i++;

      if (i > text.length) {
        clearInterval(interval);
      }

    }, 25);
  };

  // ================= FETCH HISTORY =================
  useEffect(() => {

    if (!safeUserId) return;

    const fetchHistory = async () => {
      try {

        const res = await fetch(`http://localhost:5000/api/chat-reply/history/${safeUserId}`);
        if (!res.ok) throw new Error("History fetch failed");

        const data = await res.json();

        if (data.history?.length > 0) {

          setMessages(
            data.history.map(m => ({
              role: m.role,
              text: m.text
            }))
          );

          const lastMBTI = data.history[data.history.length - 1]?.mbtiType;

          if (lastMBTI && lastMBTI !== "Unknown") {
            setCurrentMBTI(lastMBTI);
          }

        } else {

          const first = firstMessages[currentMBTI] || firstMessages.DEFAULT;
          typeGreeting(first);

        }

      } catch (err) {

        console.error("History error:", err);

        const first = firstMessages[currentMBTI] || firstMessages.DEFAULT;
        typeGreeting(first);

      }
    };

    fetchHistory();

  }, [safeUserId, currentMBTI]);

  // ================= AUTO SCROLL =================
  useEffect(() => {

    if (firstLoad.current) {
      firstLoad.current = false;
      return;
    }

    scrollToBottom();

  }, [messages]);

  if (!safeUserId) {
    return <div className="ai-mentor">გთხოვ გაიარე ავტორიზაცია 😊</div>;
  }

  // ================= SEND MESSAGE =================
  const sendMessage = async () => {

    if (!input.trim() || loading) return;

    const text = input;

    setInput("");

    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
    }

    setMessages(prev => [...prev, { role: "user", text }]);

    setLoading(true);

    try {

      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          message: text,
          type: currentMBTI,
          userId: safeUserId,
          newChat: false,
          memory: memory || {}
        })
      });

      if (!res.ok) throw new Error("Chat failed");

      const data = await res.json();

      setMessages(prev => [...prev, { role: "ai", text: data.reply }]);

      if (data.mbtiType && data.mbtiType !== "Unknown") {
        setCurrentMBTI(data.mbtiType);
      }

      setTimeout(scrollToBottom, 50);

    } catch (err) {

      console.error("Send error:", err);

      setMessages(prev => [
        ...prev,
        { role: "ai", text: "😔 ჩატი დროებით მიუწვდომელია" }
      ]);

    }

    setLoading(false);
  };

  // ================= NEW CHAT =================
  const newChat = async () => {

    try {

      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          message: "ახალი ჩატი დაიწყო",
          type: currentMBTI,
          userId: safeUserId,
          newChat: true,
          memory: memory || {}
        })
      });

      const data = await res.json();

      setMessages([{ role: "ai", text: data.reply }]);

      if (data.mbtiType && data.mbtiType !== "Unknown") {
        setCurrentMBTI(data.mbtiType);
      }

      setTimeout(scrollToBottom, 50);

      textareaRef.current?.focus();

    } catch (err) {
      console.error("New chat error:", err);
    }
  };

  return (

    <div className="ai-mentor">

      <div className="ai-header">
        Personal AI Mentor ({currentMBTI})
        <button className="new-chat-btn" onClick={newChat}>
          New Chat
        </button>
      </div>

      <div className="ai-messages">

        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}

        {loading && (
          <div className="msg ai">AI წერს...</div>
        )}

        <div ref={messagesEndRef}></div>

      </div>

      <div className="ai-input">

        <textarea
          ref={textareaRef}
          value={input}
          rows="1"
          placeholder="მომწერე..."

          onChange={(e) => {

            const el = e.target;

            setInput(el.value);

            el.style.height = "auto";

            el.style.height =
              Math.min(el.scrollHeight, 90) + "px";

          }}

          onKeyDown={(e) => {

            if (e.key === "Enter" && !e.shiftKey) {

              e.preventDefault();

              sendMessage();

            }

          }}

        />

        <button
          onClick={sendMessage}
          disabled={loading}
        >
          გაგზავნა
        </button>

      </div>

    </div>
  );
}
